import React, { useState, useEffect } from 'react';
import axios from 'axios';
import styles from './Environments.module.css'; // Import the CSS Module
import EnvironmentCRUD from '../EnvironmentCRUD/EnvironmentCRUD'; // Import the EnvironmentCRUD component
import { logParams } from '../Services/Services';

interface EnvironmentsProps {
  tenants: any[];
  onClose: () => void;
}

interface EnvironmentInfo {
  custom_hash: string;
  rpo_hash: string;
  custom_timestamp: string;
  rpo_timestamp: string;
}

const getBaseUrl = () => {
  return ''; // Replace with your actual base URL
};

const Environments: React.FC<EnvironmentsProps> = ({ tenants, onClose }) => {
  const [allEnvironments, setAllEnvironments] = useState<
    { tenantName: string; tenantId: string; environmentName: string; selected: boolean }[]
  >([]);
  const [selectedEnvironments, setSelectedEnvironments] = useState<
    {
      tenantName: string;
      environmentName: string;
      custom_hash?: string;
      rpo_hash?: string;
      custom_timestamp?: string;
      rpo_timestamp?: string;
    }[]
  >([]);
  const [loading, setLoading] = useState(true);
  const [loadingProgress, setLoadingProgress] = useState(0);
  const [showResults, setShowResults] = useState(false);
  const [showCRUD, setShowCRUD] = useState(false); // State to control the CRUD modal visibility
  const [successMessage, setSuccessMessage] = useState<string | null>(null);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);
  
  const createLogEntry = async (params: logParams) => {
    try {
      const originTenantName = tenants.find(tenant => tenant.id === params.origin_tenant)?.name || '';
      const destinationTenantName = tenants.find(tenant => tenant.id === params.destination_tenant)?.name || '';
      const now = new Date();
      const logEntry = {
        date: now.toISOString().split('T')[0],
        time: now.toTimeString().split(' ')[0],
        user: localStorage.getItem('username') || 'unknown',
        tenant: originTenantName,
        service: params.serviceName,
        action: params.action,
        origin: params.origin,
        origin_tenant: originTenantName,
        destination_tenant: destinationTenantName || '',
        destination: params.destination || '',
        result: 'In Progress',
        log_result: params.log_result
      };
      const response = await axios.post(`${getBaseUrl()}/api/logs`, logEntry);
      return response.data.id;
    } catch (error) {
      console.error('Error creating log entry:', error);
      return null;
    }
  };

  const updateLogEntry = async (logId: number, result: string, full_log?: string) => {
    try {
      const now = new Date();
      await axios.put(`${getBaseUrl()}/api/logs/${logId}`, {
        finish_date: now.toISOString().split('T')[0],
        finish_time: now.toLocaleTimeString('en-US', { hour12: false }),
        result: result,
        log_result: full_log
      });
    } catch (error) {
      console.error('Error updating log entry:', error);
    }
  };


  useEffect(() => {
    const fetchEnvironments = async () => {
      try {
        const environmentsData: { tenantName: string; tenantId: string; environmentName: string; selected: boolean }[] = [];

        for (const tenant of tenants) {
          try {
            const response = await axios.get<{ environments: string[] }>(
              `${getBaseUrl()}/api/get-environments/${tenant.id}`
            );
            response.data.environments.forEach((environment) => {
              environmentsData.push({
                tenantName: tenant.name,
                tenantId: tenant.id,
                environmentName: environment,
                selected: false, // Default to not selected
              });
            });
          } catch (error) {
            console.error(`Error fetching environments for tenant ${tenant.name}:`, error);
          }
        }

        setAllEnvironments(environmentsData);
      } catch (error) {
        console.error('Error loading environments:', error);
      } finally {
        setLoading(false);
      }
    };

    fetchEnvironments();
  }, [tenants]);

  const handleCheckboxChange = (index: number) => {
    const updatedEnvironments = [...allEnvironments];
    updatedEnvironments[index].selected = !updatedEnvironments[index].selected;
    setAllEnvironments(updatedEnvironments);
  };

  const fetchSelectedEnvironmentData = async () => {
    setLoading(true);
    setLoadingProgress(0);

    const selectedData = allEnvironments.filter((env) => env.selected);
    const totalCalls = selectedData.length;
    let completedCalls = 0;

    const results: {
      tenantName: string;
      environmentName: string;
      custom_hash?: string;
      rpo_hash?: string;
      custom_timestamp?: string;
      rpo_timestamp?: string;
    }[] = [];

    for (const env of selectedData) {
      try {
        const response = await axios.post<EnvironmentInfo>(
          `${getBaseUrl()}/api/get-rpo-hash`,
          {
            tenantId: env.tenantId,
            environmentId: env.environmentName,
          }
        );
        results.push({
          tenantName: env.tenantName,
          environmentName: env.environmentName,
          custom_hash: response.data.custom_hash,
          rpo_hash: response.data.rpo_hash,
          custom_timestamp: response.data.custom_timestamp,
          rpo_timestamp: response.data.rpo_timestamp,
        });
      } catch (error) {
        console.error(`Error fetching data for environment ${env.environmentName}:`, error);
        results.push({
          tenantName: env.tenantName,
          environmentName: env.environmentName,
        });
      }

      completedCalls++;
      setLoadingProgress(Math.floor((completedCalls / totalCalls) * 100));
    }

    setSelectedEnvironments(results);
    setShowResults(true);
    setLoading(false);
  };

  const handleRemoveEnvironment = async () => {
    const selectedEnv = allEnvironments.find((env) => env.selected);

    setSuccessMessage(null);
    setErrorMessage(null);

    if (!selectedEnv) {
      setErrorMessage('Please select an environment to remove.');
      setTimeout(() => setErrorMessage(''), 3000); // Hide after 3 seconds
      return;
    }

    const logId = await createLogEntry({
      serviceName: 'Remove Environment',
      action: 'Removal',
      origin: selectedEnv.environmentName,
      destination: selectedEnv.environmentName,
      origin_tenant: selectedEnv.tenantId,
      destination_tenant: selectedEnv.tenantId,
    });

    try {

      const response = await axios.post(`${getBaseUrl()}/api/remove-environment`, {
        tenantId: selectedEnv.tenantId,
        environment: selectedEnv.environmentName,
      });
      setAllEnvironments((prev) =>
        prev.filter(
          (env) =>
            env.tenantId !== selectedEnv.tenantId || env.environmentName !== selectedEnv.environmentName
        )
      );

      if (logId) await updateLogEntry(logId, 'Success', response.data.message);

      setSuccessMessage('Ambiente removido com sucesso!');
      setTimeout(() => setSuccessMessage(''), 3000); // Hide after 3 seconds

    } catch (error) {
      if (logId) {
        const errorMessage = axios.isAxiosError(error) && error.response?.data?.error ? error.response.data.error : 'Unknown error';
        await updateLogEntry(logId, 'Failed', errorMessage);
      }

      console.error('Falha ao remover ambiente. Verifique o log.', error);
      setErrorMessage('Falha ao remover ambiente. Verifique o log.');
      setTimeout(() => setErrorMessage(''), 3000); // Hide after 3 seconds
    }
  };


  return (
    <div className={styles.environments}>
      {loading ? (
        <div className={styles.loadingContainer}>
          <p>Carregando, aguarde... {loadingProgress}%</p>
          <div className={styles.progressBar}>
            <div
              className={styles.progress}
              style={{ width: `${loadingProgress}%` }}
            ></div>
          </div>
        </div>
      ) : showResults ? (
        <>
          <button className={styles.button} type="button" onClick={() => setShowResults(false)}>
            Voltar
          </button>
          <table className={styles.table}>
            <thead>
              <tr>
                <th>Topologia</th>
                <th>Ambiente</th>
                <th>Custom Hash</th>
                <th>RPO Hash</th>
                <th>Custom Timestamp</th>
                <th>RPO Timestamp</th>
              </tr>
            </thead>
            <tbody>
              {selectedEnvironments.map((env, index) => (
                <tr key={index}>
                  <td>{env.tenantName}</td>
                  <td>{env.environmentName}</td>
                  <td>{env.custom_hash || 'n/a'}</td>
                  <td>{env.rpo_hash || 'n/a'}</td>
                  <td>{env.custom_timestamp || 'n/a'}</td>
                  <td>{env.rpo_timestamp || 'n/a'}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </>
      ) : (
        <>
          <button className={styles.button} type="button" onClick={fetchSelectedEnvironmentData}>
            Informações
          </button>
          <button className={styles.button} type="button" onClick={() => setShowCRUD(true)}>
            Novo Ambiente
          </button>
          <button className={styles.button} type="button" onClick={handleRemoveEnvironment}>
            Remover Ambiente
          </button>
          <button className={styles.button} type="button" onClick={onClose}>
            Voltar
          </button>
          <div>
            {successMessage && <div className={styles.successballoon}>{successMessage}</div>}
            {errorMessage && <div className={styles.failedballoon}>{errorMessage}</div>}</div>


          {showCRUD && <EnvironmentCRUD tenants={tenants} onClose={() => setShowCRUD(false)} />}
          <table className={styles.table}>
            <thead>
              <tr>
                <th>Selecionar</th>
                <th>Topologia</th>
                <th>Ambiente</th>
              </tr>
            </thead>
            <tbody>
              {allEnvironments.map((env, index) => (
                <tr key={index}>
                  <td>
                    <input
                      type="checkbox"
                      checked={env.selected}
                      onChange={() => handleCheckboxChange(index)}
                    />
                  </td>
                  <td>{env.tenantName}</td>
                  <td>{env.environmentName}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </>
      )}
    </div>
  );
};

export default Environments;
