import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import axios from 'axios';
import './HeaderBar.css';

interface HeaderBarProps {
  username: string;
}

const HeaderBar: React.FC<HeaderBarProps> = ({ username }) => {
  const [fullName, setFullName] = useState('');

  useEffect(() => {
    const fetchFullName = async () => {
      try {
        const response = await axios.get(`/api/users/${username}`);
        setFullName(response.data.name);
      } catch (error) {
        console.error('Error fetching user info:', error);
      }
    };

    fetchFullName();
  }, [username]);

  return (
    <div className="header-bar">
      {localStorage.getItem('tenant_logo') && localStorage.getItem('tenant_logo') !== 'null' && (
        <div className="header-logo-container">
          <img 
            src={`data:image/png;base64,${localStorage.getItem('tenant_logo')}`} 
            alt="logo" 
            className="header-logo" 
            style={{ width: '110px', height: 'auto', marginLeft: '20px' }} 
          />
        </div>
      )}
      <div className="app-client"><h4>{localStorage.getItem('tenant_name') || ''}</h4></div>
      <div className="config-menu">
        <button className="config-button">{fullName || username}</button>
        <div className="dropdown-content">
          <Link to="/">Sair</Link>
        </div>
      </div>
    </div>
  );
};

export default HeaderBar;